/// Convert an integer to a `Method` variant. Returns -1 on invalid input.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn spikard_method_from_i32(value: i32) -> i32 {
    match value {
        0 => 0, // Get
        1 => 1, // Post
        2 => 2, // Put
        3 => 3, // Patch
        4 => 4, // Delete
        5 => 5, // Head
        6 => 6, // Options
        7 => 7, // Trace
        _ => {
            set_last_error(1, "Invalid Method variant");
            -1
        }
    }
}

/// Convert a `Method` variant name (C string) to its integer value. Returns -1 on invalid input.
/// # Safety
/// Caller must ensure `ptr` is a valid pointer to a `c_char` or null.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn spikard_method_from_str(name: *const c_char) -> i32 {
    if name.is_null() {
        set_last_error(1, "Null pointer passed for enum name");
        return -1;
    }
    // SAFETY: null check above guarantees name is a valid pointer; string is valid UTF-8 from caller.
    let s = match unsafe { CStr::from_ptr(name) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in enum name");
            return -1;
        }
    };
    match s {
        "Get" => 0,
        "Post" => 1,
        "Put" => 2,
        "Patch" => 3,
        "Delete" => 4,
        "Head" => 5,
        "Options" => 6,
        "Trace" => 7,
        _ => {
            set_last_error(1, "Unknown Method variant");
            -1
        }
    }
}

/// Convert an integer to a `SecuritySchemeInfo` variant. Returns -1 on invalid input.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn spikard_security_scheme_info_from_i32(value: i32) -> i32 {
    match value {
        0 => 0, // Http
        1 => 1, // ApiKey
        _ => {
            set_last_error(1, "Invalid SecuritySchemeInfo variant");
            -1
        }
    }
}

/// Convert a `SecuritySchemeInfo` variant name (C string) to its integer value. Returns -1 on invalid input.
/// # Safety
/// Caller must ensure `ptr` is a valid pointer to a `c_char` or null.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn spikard_security_scheme_info_from_str(name: *const c_char) -> i32 {
    if name.is_null() {
        set_last_error(1, "Null pointer passed for enum name");
        return -1;
    }
    // SAFETY: null check above guarantees name is a valid pointer; string is valid UTF-8 from caller.
    let s = match unsafe { CStr::from_ptr(name) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in enum name");
            return -1;
        }
    };
    match s {
        "Http" => 0,
        "ApiKey" => 1,
        _ => {
            set_last_error(1, "Unknown SecuritySchemeInfo variant");
            -1
        }
    }
}

/// Create a simple schema configuration with only Query type.
///
/// This is a convenience function for schemas that only have queries.
///
/// # Returns
///
/// A `QueryOnlyConfig` with default settings
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn spikard_schema_query_only() -> *mut spikard_graphql::QueryOnlyConfig {
    clear_last_error();
    let result = spikard_graphql::schema_query_only();
    Box::into_raw(Box::new(result))
}

